     1→import { execFileSync } from "node:child_process";
     2→import { readFileSync } from "node:fs";
     3→import os from "node:os";
     4→import path from "node:path";
     5→import { UserError } from "../errors.ts";
     6→import type { AgentConfig } from "../types.ts";
     7→
     8→export function resolveHome(): string {
     9→  if (process.platform === "win32") {
    10→    return os.homedir();
    11→  }
    12→
    13→  const sudoUser = process.env["SUDO_USER"];
    14→  if (sudoUser) {
    15→    return lookupHomeForUser(sudoUser);
    16→  }
    17→
    18→  return os.homedir();
    19→}
    20→
    21→export function lookupHomeForUserWith(
    22→  username: string,
    23→  platform: NodeJS.Platform,
    24→  execFileFn: typeof execFileSync,
    25→  readFileFn: typeof readFileSync
    26→): string {
    27→  // Method 1: getent passwd (Linux/POSIX — handles LDAP, NIS, local via NSS)
    28→  if (platform !== "darwin") {
    29→    try {
    30→      const out = execFileFn("getent", ["passwd", username], {
    31→        encoding: "utf8",
    32→        stdio: ["ignore", "pipe", "ignore"],
    33→      }).trim();
    34→      const home = (out as string).split(":")[5];
    35→      if (typeof home === "string" && home.startsWith("/")) return home;
    36→    } catch {
    37→      // getent unavailable or user not found — try next method
    38→    }
    39→  }
    40→
    41→  // Method 2: dscl (macOS directory services)
    42→  if (platform === "darwin") {
    43→    try {
    44→      const out = execFileFn(
    45→        "dscl",
    46→        [".", "-read", `/Users/${username}`, "NFSHomeDirectory"],
    47→        { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] }
    48→      ).trim();
    49→      const home = (out as string).replace(/^NFSHomeDirectory:\s*/, "").trim();
    50→      if (home.startsWith("/")) return home;
    51→    } catch {
    52→      // dscl unavailable or user record not found — try next method
    53→    }
    54→  }
    55→
    56→  // Method 3: parse /etc/passwd directly (universal POSIX fallback)
    57→  try {
    58→    const passwd = readFileFn("/etc/passwd", "utf8") as string;
    59→    for (const line of passwd.split("\n")) {
    60→      const parts = line.split(":");
    61→      if (parts[0] === username) {
    62→        const home = parts[5];
    63→        if (typeof home === "string" && home.startsWith("/")) return home;
    64→      }
    65→    }
    66→  } catch {
    67→    // /etc/passwd unavailable — fall through to error
    68→  }
    69→
    70→  throw new UserError(
    71→    "RESOLVE_FAILED",
    72→    `Cannot determine home directory for user "${username}". ` +
    73→      `Tried getent, dscl, and /etc/passwd. ` +
    74→      `Run without sudo, or set HOME to the correct path before invoking with sudo.`
    75→  );
    76→}
    77→
    78→function lookupHomeForUser(username: string): string {
    79→  return lookupHomeForUserWith(username, process.platform, execFileSync, readFileSync);
    80→}
    81→
    82→export function getPlatformKey(): "posix" | "windows" {
    83→  return process.platform === "win32" ? "windows" : "posix";
    84→}
    85→
    86→export function getDeployMethod(): "symlink" | "copy" {
    87→  return process.platform === "win32" ? "copy" : "symlink";
    88→}
    89→
