    32→      throw new UserError(
    33→        "DEPLOY_FAILED",
    34→        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
    35→      );
    36→    }
    37→
    38→    try {
    39→      const realSource = await realpath(source);
    40→      if (realSource !== realRoot && !realSource.startsWith(realRoot + path.sep)) {
    41→        throw new UserError(
    42→          "DEPLOY_FAILED",
    43→          `Skill path "${skill.path}" resolves outside the repository root via symlink: ${source} -> ${realSource}`
    44→        );
    45→      }
    46→    } catch (err) {
    47→      if (err instanceof UserError) throw err;
    48→      // Source doesn't exist yet — will be caught during execute
    49→    }
