    51→    for (const agentId of skill.agents) {
    52→      if (!detectedAgents.includes(agentId)) continue;
    53→
    54→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    55→      if (!agent) continue;
    56→
    57→      const target = resolveAgentSkillPath(agent, skill.name, home);
    58→
    59→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    60→    }
    61→  }
    62→
    63→  return actions;
    64→}
    65→
    66→export async function executeDeploy(
    67→  actions: DeployAction[],
    68→  dryRun: boolean,
    69→  verbose: boolean
    70→): Promise<{ succeeded: number; failed: Array<{ action: DeployAction; error: string }> }> {
    71→  let succeeded = 0;
    72→  const failed: Array<{ action: DeployAction; error: string }> = [];
    73→
