    32→export async function isOwnedByInceptionEngine(
    33→  targetPath: string,
    34→  stat: Stats
    35→): Promise<boolean> {
    36→  const totemLocation = stat.isSymbolicLink()
    37→    ? await resolveSymlinkTotemPath(targetPath)
    38→    : path.join(targetPath, TOTEM_FILE);
    39→
    40→  if (!totemLocation) return false;
    41→
    42→  try {
    43→    const content = await readFile(totemLocation, "utf-8");
    44→    return content.startsWith(TOTEM_HEADER);
    45→  } catch {
    46→    return false;
    47→  }
    48→}
    49→
    50→async function resolveSymlinkTotemPath(targetPath: string): Promise<string | null> {
    51→  try {
    52→    const linkTarget = await readlink(targetPath);
    53→    const resolved = path.resolve(path.dirname(targetPath), linkTarget);
    54→    await access(resolved);
    55→    return path.join(resolved, TOTEM_FILE);
    56→  } catch {
    57→    return null;
    58→  }
    59→}
