     1→import { lstat, unlink, rm } from "node:fs/promises";
     2→import { AGENT_REGISTRY, AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
     3→import { resolveAgentSkillPath } from "./resolve.ts";
     4→import type { AgentId, Manifest, RevertAction } from "../types.ts";
     5→import { logger } from "../logger.ts";
     6→import { isOwnedByInceptionEngine } from "./ownership.ts";
     7→
     8→export function planRevert(
     9→  manifest: Manifest,
    10→  detectedAgents: AgentId[],
    11→  home: string
    12→): RevertAction[] {
    13→  const actions: RevertAction[] = [];
    14→
    15→  for (const skill of manifest.skills) {
    16→    for (const agentId of skill.agents) {
    17→      if (!detectedAgents.includes(agentId)) continue;
    18→
    19→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    20→      if (!agent) continue;
    21→
    22→      const target = resolveAgentSkillPath(agent, skill.name, home);
    23→      actions.push({ skill: skill.name, agent: agentId, target });
    24→    }
    25→  }
    26→
    27→  return actions;
    28→}
    29→
    30→export function planRevertAll(
    31→  manifest: Manifest,
    32→  home: string
    33→): RevertAction[] {
    34→  const actions: RevertAction[] = [];
    35→
    36→  for (const skill of manifest.skills) {
    37→    for (const agentId of skill.agents) {
    38→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    39→      if (!agent) continue;
    40→
    41→      const target = resolveAgentSkillPath(agent, skill.name, home);
    42→      actions.push({ skill: skill.name, agent: agentId, target });
    43→    }
    44→  }
    45→
    46→  return actions;
    47→}
    48→
    49→export async function executeRevert(
    50→  actions: RevertAction[],
    51→  dryRun: boolean,
    52→  verbose: boolean
    53→): Promise<{ succeeded: number; skipped: number }> {
    54→  let succeeded = 0;
    55→  let skipped = 0;
    56→
    57→  for (const action of actions) {
    58→    const label = `${action.skill} -> ${action.agent}`;
    59→
    60→    let stat: Awaited<ReturnType<typeof lstat>>;
    61→    try {
    62→      stat = await lstat(action.target);
    63→    } catch {
    64→      logger.skip(label, "(not found, skipping)");
    65→      skipped++;
    66→      continue;
    67→    }
    68→
    69→    if (!(await isOwnedByInceptionEngine(action.target, stat))) {
    70→      logger.warn(label, `skipping: ${action.target} does not have inception-engine ownership proof — not managed by inception-engine`);
    71→      skipped++;
    72→      continue;
    73→    }
    74→
    75→    if (dryRun) {
    76→      logger.plan(label);
    77→      if (verbose) {
    78→        logger.detail(`would remove: ${action.target}`);
    79→      }
    80→      succeeded++;
    81→      continue;
    82→    }
    83→
    84→    try {
    85→      if (stat.isSymbolicLink()) {
    86→        await unlink(action.target);
    87→      } else {
    88→        await rm(action.target, { recursive: true });
    89→      }
    90→      logger.ok(label);
    91→      if (verbose) {
    92→        logger.detail(`removed: ${action.target}`);
    93→      }
    94→      succeeded++;
    95→    } catch (err) {
    96→      const msg = err instanceof Error ? err.message : String(err);
    97→      logger.fail(label, msg);
    98→    }
    99→  }
   100→
   101→  return { succeeded, skipped };
   102→}
   103→

